function InjectStyles() {
  useEffect(() => {
    const tag = document.createElement("style");
    tag.setAttribute("data-dh-site-css", "true");
    tag.textContent = css;
    document.head.appendChild(tag);
    return () => tag.remove();
  }, []);
  return null;
}

