function art(id, title, date, medium, theme, flow, image, description, url = "https://www.metmuseum.org/art/collection") {
  return {
    id,
    title,
    date,
    medium,
    theme,
    flow,
    image: `/artworks/${image}`,
    description,
    url,
  };
}

